class PaymentGatewayClient {
  final PaymentConfig config;
  final http.Client _httpClient;

  PaymentGatewayClient({
    required this.config,
    http.Client? httpClient,
  }) : _httpClient = httpClient ?? http.Client();

  Future<Map<String, dynamic>> createOrder({
    required String customerId,
    required String currency,
    required double amount,
    required PaymentMethodType method,
    Map<String, dynamic> metadata = const {},
  }) async {
    final body = {
      'customerId': customerId,
      'currency': currency,
      'amount': amount,
      'method': method.name,
      'metadata': metadata,
    };
    return _post('/payments/orders', body);
  }

  Future<Map<String, dynamic>> verifyInAppPurchase({
    required String platform,
    required String productId,
    required String transactionId,
    required String receiptData,
  }) async {
    return _post('/payments/iap/verify', {
      'platform': platform,
      'productId': productId,
      'transactionId': transactionId,
      'receiptData': receiptData,
    });
  }

  Future<Map<String, dynamic>> authorizeWalletPayment({
    required WalletPaymentResult walletResult,
    required String currency,
    required double amount,
    Map<String, dynamic> metadata = const {},
  }) async {
    return _post('/payments/wallets/authorize', {
      'provider': walletResult.provider.name,
      'orderId': walletResult.orderId,
      'paymentToken': walletResult.paymentToken,
      'currency': currency,
      'amount': amount,
      'metadata': metadata,
      'rawData': walletResult.rawData,
    });
  }

  Future<Map<String, dynamic>> capturePayment({
    required String paymentId,
    required double amount,
  }) async {
    return _post('/payments/capture', {
      'paymentId': paymentId,
      'amount': amount,
    });
  }

  Future<Map<String, dynamic>> refundPayment({
    required String paymentId,
    required double amount,
    String? reason,
  }) async {
    return _post('/payments/refund', {
      'paymentId': paymentId,
      'amount': amount,
      'reason': reason,
    });
  }

  Future<Map<String, dynamic>> tokenizeCardWithBackend({
    required Map<String, dynamic> encryptedCardPayload,
  }) async {
    return _post('/payments/cards/tokenize', encryptedCardPayload);
  }

  Future<Map<String, dynamic>> _post(String path, Map<String, dynamic> body) async {
    final uri = config.backendBaseUrl.resolve(path);
    final payload = jsonEncode(body);
    final signature = _signPayload(payload);

    final response = await _httpClient
        .post(
          uri,
          headers: {
            HttpHeaders.contentTypeHeader: 'application/json',
            'X-Merchant-Id': config.merchantId,
            'X-Payload-Signature': signature,
          },
          body: payload,
        )
        .timeout(config.networkTimeout);

    if (response.statusCode < 200 || response.statusCode >= 300) {
      throw PaymentException(
        'gateway_http_error',
        'Gateway request failed with status ${response.statusCode}',
        response.body,
      );
    }

    final decoded = jsonDecode(response.body);
    if (decoded is! Map<String, dynamic>) {
      throw PaymentException('gateway_invalid_response', 'Invalid gateway response');
    }
    return decoded;
  }

  String _signPayload(String payload) {
    final bytes = utf8.encode('${config.merchantId}:$payload');
    return sha256.convert(bytes).toString();
  }

  void dispose() {
    _httpClient.close();
  }
}

class SecureCardTokenizer {
  static const MethodChannel _channel = MethodChannel('payment_module/secure_card');

  Future<Map<String, dynamic>> tokenize({
    required String cardNumber,
    required String expiryMonth,
    required String expiryYear,
    required String cvv,
    String? cardholderName,
  }) async {
    final result = await _channel.invokeMethod<Map<dynamic, dynamic>>(
      'tokenizeCard',
      {
        'cardNumber': cardNumber,
        'expiryMonth': expiryMonth,
        'expiryYear': expiryYear,
        'cvv': cvv,
        'cardholderName': cardholderName,
      },
    );

    if (result == null) {
