class MobileWalletService {
  static const MethodChannel _channel = MethodChannel('payment_module/mobile_wallet');
  final PaymentConfig config;

  MobileWalletService(this.config);

  Future<bool> isWalletAvailable(WalletProvider provider) async {
    final available = await _channel.invokeMethod<bool>('isWalletAvailable', {
      'provider': provider.name,
      'environment': config.environment.name,
    });
    return available ?? false;
  }

  Future<WalletPaymentResult> presentWallet(WalletPaymentRequest request) async {
    final result = await _channel.invokeMethod<Map<dynamic, dynamic>>(
      'presentWallet',
      {
        ...request.toJson(),
        'environment': config.environment.name,
        'merchantId': config.merchantId,
        'merchantDisplayName': config.merchantDisplayName,
        'applePayMerchantIdentifier': config.applePayMerchantIdentifier,
        'googlePayGatewayName': config.googlePayGatewayName,
        'googlePayGatewayMerchantId': config.googlePayGatewayMerchantId,
      },
    );

    if (result == null) {
      throw PaymentException('wallet_cancelled', 'Wallet payment was cancelled');
    }

    final map = result.map((key, value) => MapEntry(key.toString(), value));
    return WalletPaymentResult(
      paymentToken: map['paymentToken']?.toString() ?? '',
      orderId: map['orderId']?.toString() ?? request.orderId,
      provider: request.provider,
      rawData: map,
    );
  }
}

class InAppPurchaseService {
  final PaymentConfig config;
  final InAppPurchase _iap = InAppPurchase.instance;
  StreamSubscription<List<PurchaseDetails>>? _purchaseSubscription;
  final StreamController<PaymentTransaction> _transactionController =
      StreamController<PaymentTransaction>.broadcast();

  List<ProductDetails> _products = [];
  bool _initialized = false;

  InAppPurchaseService(this.config);

  Stream<PaymentTransaction> get transactions => _transactionController.stream;

  List<PaymentProduct> get products =>
      _products.map(PaymentProduct.fromProductDetails).toList(growable: false);

  Future<void> initialize({
    required Future<void> Function(PurchaseDetails purchase) onServerVerificationRequired,
  }) async {
    if (_initialized) return;

    final available = await _iap.isAvailable();
    if (!available) {
      throw PaymentException('iap_unavailable', 'In-app purchases are unavailable');
    }

    final response = await _iap.queryProductDetails(config.allProductIds);
    if (response.error != null) {
      throw PaymentException(
        'iap_product_query_failed',
        response.error!.message,
        response.error,
      );
    }

    _products = response.productDetails;

    _purchaseSubscription = _iap.purchaseStream.listen(
      (purchases) async {
        for (final purchase in purchases) {
          try {
            await onServerVerificationRequired(purchase);
          } catch (e) {
            _transactionController.add(
              PaymentTransaction(
                id: purchase.purchaseID ?? '',
                method: PaymentMethodType.inAppPurchase,
                status: PaymentStatus.failed,
                productId: purchase.productID,
                receipt: _extractReceipt(purchase),
                createdAt: DateTime.now().toUtc(),
                message: e.toString(),
                metadata: {'source': 'purchaseStream'},
              ),
            );
          }
        }
      },
      onError: (error) {
        _transactionController.add(
          PaymentTransaction(
            id: '',
            method: PaymentMethodType.inAppPurchase,
            status: PaymentStatus.failed,
            createdAt: DateTime.now().toUtc(),
            message: error.toString(),
          ),
        );
      },
    );

    _initialized = true;
  }

  Future<List<PaymentProduct>> loadProducts() async {
    if (!_initialized) {
      throw PaymentException('iap_not_initialized', 'Initialize IAP service first');
    }
    return products;
  }

  Future<void> buyProduct(String productId) async {
    final product = _products.where((p) => p.id == productId).cast<ProductDetails?>().firstWhere(
          (p) => p != null,
          orElse: () => null,
        );
    if (product == null) {
      throw PaymentException('product_not_found', 'Product $productId not found');
    }

    final purchaseParam = PurchaseParam(productDetails: product);
    if (config.consumableProductIds.contains(productId)) {
      await _iap.buyConsumable(purchaseParam: purchaseParam, autoConsume: Platform.isAndroid);
    } else {
      await _iap.buyNonConsumable(purchaseParam: purchaseParam);
    }
  }

  Future<void> restorePurchases() async {
    await _iap.restorePurchases();
  }

  Future<void> completePurchase(PurchaseDetails purchase) async {
    if (purchase.pendingCompletePurchase) {
      await _iap.completePurchase(purchase);
    }
  }

  PaymentStatus mapPurchaseStatus(PurchaseStatus status) {
    switch (status) {
      case PurchaseStatus.pending:
        return PaymentStatus.pending;
      case PurchaseStatus.purchased:
        return PaymentStatus.purchased;
      case PurchaseStatus.restored:
        return PaymentStatus.restored;
      case PurchaseStatus.error:
        return PaymentStatus.failed;
      case PurchaseStatus.canceled:
        return PaymentStatus.cancelled;
    }
  }

  String _extractReceipt(PurchaseDetails purchase) {
    try {
      return purchase.verificationData.serverVerificationData;
    } catch (_) {
      return '';
    }
  }

  void emitVerifiedTransaction(PurchaseDetails purchase, Map<String, dynamic> verification) {
    _transactionController.add(
      PaymentTransaction(
        id: purchase.purchaseID ?? '',
        method: PaymentMethodType.inAppPurchase,
        status: mapPurchaseStatus(purchase.status),
        productId: purchase.productID,
        receipt: _extractReceipt(purchase),
        token: verification['token']?.toString(),
        orderId: verification['orderId']?.toString(),
        createdAt: DateTime.now().toUtc(),
        metadata: verification,
      ),
    );
  }

  Future<void> dispose() async {
    await _purchaseSubscription?.cancel();
    await _transactionController.close();
  }
}

class PaymentProcessor {
  final PaymentConfig config;
  final PaymentGatewayClient gatewayClient;
  final InAppPurchaseService inAppPurchaseService;
  final MobileWalletService mobileWalletService;
  final SecureCardTokenizer secureCardTokenizer;

  final StreamController<PaymentTransaction> _events =
      StreamController<PaymentTransaction>.broadcast();

  PaymentProcessor({
    required this.config,
    PaymentGatewayClient? gatewayClient,
    InAppPurchaseService? inAppPurchaseService,
    MobileWalletService? mobileWalletService,
    SecureCardTokenizer? secureCardTokenizer,
  })  : gatewayClient = gatewayClient ?? PaymentGatewayClient(config: config),
        inAppPurchaseService = inAppPurchaseService ?? InAppPurchaseService(config),
        mobileWalletService = mobileWalletService ?? MobileWalletService(config),
        secureCardTokenizer = secureCardTokenizer ?? SecureCardTokenizer();

  Stream<PaymentTransaction> get events => _events.stream;

  PaymentPlatform get currentPlatform {
    if (Platform.isIOS) return PaymentPlatform.ios;
    if (Platform.isAndroid) return PaymentPlatform.android;
    return PaymentPlatform.unknown;
  }

  Future<void> initialize() async {
    await inAppPurchaseService.initialize(
      onServerVerificationRequired: (purchase) async {
        final verification = await gatewayClient.verifyInAppPurchase(
          platform: currentPlatform.name,
          productId: purchase.productID,
          transactionId: purchase.purchaseID ?? '',
          receiptData: purchase.verificationData.serverVerificationData,
        );

        inAppPurchaseService.emitVerifiedTransaction(purchase, verification);
        await inAppPurchaseService.completePurchase(purchase);

        _events.add(
          PaymentTransaction(
            id: purchase.purchaseID ?? '',
            method: PaymentMethodType.inAppPurchase,
            status: inAppPurchaseService.mapPurchaseStatus(purchase.status),
            productId: purchase.productID,
            receipt: purchase.verificationData.serverVerificationData,
            token: verification['token']?.toString(),
            orderId: verification['orderId']?.toString(),
            createdAt: DateTime.now().toUtc(),
            metadata: verification,
          ),
        );
      },
    );

    inAppPurchaseService.transactions.listen(_events.add);
  }

  Future<List<PaymentProduct>> loadProducts() {
    return inAppPurchaseService.loadProducts();
  }

  Future<void> purchaseInAppProduct(String productId) {
    return inAppPurchaseService.buyProduct(productId);
  }

  Future<void> restoreInAppPurchases() {
    return inAppPurchaseService.restorePurchases();
  }

  Future<bool> isWalletAvailable(WalletProvider provider) {
    return mobileWalletService.isWalletAvailable(provider);
  }

  Future<PaymentTransaction> processWalletPayment({
    required WalletPaymentRequest request,
  }) async {
    final walletResult = await mobileWalletService.presentWallet(request);

    final authorization = await gatewayClient.authorizeWalletPayment(
      walletResult: walletResult,
      currency: request.currencyCode,
      amount: request.amount,
      metadata: request.metadata,
    );

    final transaction = PaymentTransaction(
      id: authorization['paymentId']?.toString() ?? walletResult.orderId,
      method: request.provider == WalletProvider.applePay
          ? PaymentMethodType.applePay
          : PaymentMethodType.googlePay,
      status: _parseStatus(authorization['status']?.toString()),
      orderId: walletResult.orderId,
      token: walletResult.paymentToken,
      currency: request.currencyCode,
      amount: request.amount,
      createdAt: DateTime.now().toUtc(),
      metadata: authorization,
    );

    _events.add(transaction);
    return transaction;
  }

  Future<PaymentTransaction> tokenizeAndCreateCardPayment({
    required String customerId,
    required String currency,
    required double amount,
    required String cardNumber,
    required String expiryMonth,
    required String expiryYear,
    required String cvv,
    String? cardholderName,
    Map<String, dynamic> metadata = const {},
  }) async {
    final encryptedPayload = await secureCardTokenizer.tokenize(
      cardNumber: cardNumber,
      expiryMonth: expiryMonth,
      expiryYear: expiryYear,
      cvv: cvv,
      cardholderName: cardholderName,
    );

    final tokenized = await gatewayClient.tokenizeCardWithBackend(
      encryptedCardPayload: encryptedPayload,
    );

    final order = await gatewayClient.createOrder(
      customerId: customerId,
      currency: currency,
      amount: amount,
      method: PaymentMethodType.cardTokenized,
      metadata: {
        ...metadata,
        'cardToken': tokenized['cardToken'],
      },
    );

    final transaction = PaymentTransaction(
      id: order['paymentId']?.toString() ?? order['orderId']?.toString() ?? '',
      method: PaymentMethodType.cardTokenized,
      status: _parseStatus(order['status']?.toString()),
      orderId: order['orderId']?.toString(),
      token: tokenized['cardToken']?.toString(),
      currency: currency,
      amount: amount,
      createdAt: DateTime.now().toUtc(),
      metadata: {
        ...tokenized,
        ...order,
      },
    );

    _events.add(transaction);
    return transaction;
  }

  Future<PaymentTransaction> capturePayment({
    required String paymentId,
    required double amount,
  }) async {
    final result = await gatewayClient.capturePayment(paymentId: paymentId, amount: amount);
    final transaction = PaymentTransaction(
      id: paymentId,
      method: PaymentMethodType.cardTokenized,
      status: _parseStatus(result['status']?.toString()),
      amount: amount,
      createdAt: DateTime.now().toUtc(),
      metadata: result,
    );
    _events.add(transaction);
    return transaction;
  }

  Future<PaymentTransaction> refundPayment({
    required String paymentId,
    required double amount,
    String? reason,
  }) async {
    final result = await gatewayClient.refundPayment(
      paymentId: paymentId,
      amount: amount,
      reason: reason,
    );
    final transaction = PaymentTransaction(
      id: paymentId,
      method: PaymentMethodType.cardTokenized,
      status: PaymentStatus.refunded,
      amount: amount,
      createdAt: DateTime.now().toUtc(),
      message: reason,
      metadata: result,
    );
    _events.add(transaction);
    return transaction;
  }

  PaymentStatus _parseStatus(String? status) {
    switch (status?.toLowerCase()) {
      case 'pending':
        return PaymentStatus.pending;
      case 'authorized':
        return PaymentStatus.authorized;
      case 'captured':
        return PaymentStatus.captured;
      case 'purchased':
        return PaymentStatus.purchased;
      case 'restored':
        return PaymentStatus.restored;
      case 'cancelled':
      case 'canceled':
        return PaymentStatus.cancelled;
      case 'refunded':
        return PaymentStatus.refunded;
      default:
        return PaymentStatus.failed;
    }
  }

  Future<void> dispose() async {
    await inAppPurchaseService.dispose();
    gatewayClient.dispose();
    await _events.close();
  }
}

class PaymentCompliance {
  static void assertPciSafeUsage({
    required bool cardDataTouchesBackendOnlyAsTokenizedPayload,
    required bool noSensitiveDataLogged,
    required bool tlsEnabled,
  }) {
    if (!cardDataTouchesBackendOnlyAsTokenizedPayload) {
      throw PaymentException(
        'pci_violation',
        'Raw card data must never be sent directly to application backend',
      );
    }
    if (!noSensitiveDataLogged) {
      throw PaymentException(
        'pci_violation',
        'Sensitive payment data logging is prohibited',
      );
    }
    if (!tlsEnabled) {
      throw PaymentException(
        'pci_violation',
        'TLS is required for all payment traffic',
      );
    }
  }
}

class PaymentModule {
  final PaymentProcessor processor;

  PaymentModule._(this.processor);

  static Future<PaymentModule> bootstrap(PaymentConfig config) async {
    PaymentCompliance.assertPciSafeUsage(
      cardDataTouchesBackendOnlyAsTokenizedPayload: true,
      noSensitiveDataLogged: true,
      tlsEnabled: config.backendBaseUrl.scheme == 'https',
    );

    final processor = PaymentProcessor(config: config);
    await processor.initialize();
    return PaymentModule._(processor);
  }
}